from math import gcd
from functools import reduce
class Solution:
    def countGoodSubseq(self, nums, p, queries):
        arr = list(nums)
        n = len(arr)
        cnt = 0
        for ind, val in queries:
            arr[ind] = val
            S = [x for x in arr if x % p == 0]
            good = False
            if S:
                g = reduce(gcd, S)
                if len(S) < n:
                    good = (g == p)
                elif g == p:
                    prefix = [0] * (n + 1)
                    suffix = [0] * (n + 1)
                    for i in range(n):
                        prefix[i + 1] = gcd(prefix[i], arr[i])
                    for i in range(n - 1, -1, -1):
                        suffix[i] = gcd(suffix[i + 1], arr[i])
                    for i in range(n):
                        if gcd(prefix[i], suffix[i + 1]) == p:
                            good = True
                            break
            if good:
                cnt += 1
        return cnt

