function gcdJS(a, b) {
    a = Math.abs(a); b = Math.abs(b);
    while (b) { [a, b] = [b, a % b]; }
    return a;
}
var countGoodSubseq = function(nums, p, queries) {
    const arr = nums.slice();
    const n = arr.length;
    let cnt = 0;
    for (const [ind, val] of queries) {
        arr[ind] = val;
        const S = arr.filter(x => x % p === 0);
        let good = false;
        if (S.length > 0) {
            let g = S.reduce((a, b) => gcdJS(a, b));
            if (S.length < n) {
                good = (g === p);
            } else if (g === p) {
                const prefix = new Array(n + 1).fill(0);
                const suffix = new Array(n + 1).fill(0);
                for (let i = 0; i < n; i++) prefix[i + 1] = gcdJS(prefix[i], arr[i]);
                for (let i = n - 1; i >= 0; i--) suffix[i] = gcdJS(suffix[i + 1], arr[i]);
                for (let i = 0; i < n; i++) {
                    if (gcdJS(prefix[i], suffix[i + 1]) === p) {
                        good = true;
                        break;
                    }
                }
            }
        }
        if (good) cnt++;
    }
    return cnt;
};
